const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length < 1) throw new Error('Payload must have clip_prompts array (got: ' + JSON.stringify(body.clip_prompts) + ')');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  word_timings: body.word_timings,
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now()
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const data           = $input.first().json;
const jobId          = data.job_id;
const videoUrls      = data.video_urls;
const subtitleChunks = data.subtitle_chunks || [];
const audioDuration  = data.audio_duration || 30;
const N              = videoUrls.length;

const n8nIn   = '/data/ffmpeg/input';
const n8nOut  = '/data/ffmpeg/output';
const contIn  = '/ffmpeg/input';
const contOut = '/ffmpeg/output';

if (!fs.existsSync(n8nIn))  fs.mkdirSync(n8nIn,  { recursive: true });
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, timeout) {
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: timeout || 120000 }); }
  catch(e) { out = ((e.stdout || '') + (e.stderr || '') + (e.message || '')).toString(); }
  return out;
}

console.log('Assembling ' + N + ' clips | audio: ' + audioDuration.toFixed(1) + 's');

// ━ STEP 1: Download all clips ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
for (let i = 0; i < N; i++) {
  const dest = contIn + '/' + jobId + '_clip' + i + '.mp4';
  const out = run(
    'docker exec ffmpeg-runner curl -sL --max-time 90 -o "' + dest + '" "' + videoUrls[i] + '" && echo DL_OK',
    100000
  );
  if (!out.includes('DL_OK'))
    throw new Error('Clip ' + i + ' download failed: ' + out.slice(-200));
}

// ━ STEP 2: Normalize each clip to 1080x1920 (9:16) — clips are already 5s from API ━
for (let i = 0; i < N; i++) {
  const src  = contIn  + '/' + jobId + '_clip' + i + '.mp4';
  const norm = contIn  + '/' + jobId + '_clip' + i + '_norm.mp4';
  const out  = run(
    'docker exec ffmpeg-runner ffmpeg -y -i "' + src + '" ' +
    '-vf "scale=1080:1920:force_original_aspect_ratio=decrease,' +
         'pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" ' +
    '-r 24 -c:v libx264 -crf 20 -preset fast -an "' + norm + '" 2>&1 && echo NORM_OK',
    180000
  );
  if (!out.includes('NORM_OK'))
    throw new Error('Normalize clip ' + i + ' failed: ' + out.slice(-300));
}

// ━ STEP 3: Concat with XFADE transitions ━━━━━━━━━━━━━━━━━━━━━━━━
const FADE_DUR = 0.3;
const CLIP_DUR = 5.0;  // each clip trimmed to 5s
const NET      = CLIP_DUR - FADE_DUR; // 4.7s net per clip → 6 clips = ~30s total

let withTransitions;
if (N === 1) {
  withTransitions = contIn + '/' + jobId + '_clip0_norm.mp4';
} else {
  const inputs  = Array.from({ length: N }, (_, i) =>
    '-i "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"'
  ).join(' ');

  let filterParts = [];
  let prevLabel   = '[0:v]';
  for (let i = 1; i < N; i++) {
    const offset   = (i * NET).toFixed(1);
    const outLabel = (i === N - 1) ? '[vout]' : '[x' + i + ']';
    filterParts.push(prevLabel + '[' + i + ':v]xfade=transition=fade:duration=' + FADE_DUR + ':offset=' + offset + outLabel);
    prevLabel = outLabel;
  }
  const filterComplex = filterParts.join('; ');
  const xfadeOut = contIn + '/' + jobId + '_xfade.mp4';
  const xfadeCmd =
    'docker exec ffmpeg-runner ffmpeg -y ' + inputs + ' ' +
    '-filter_complex "' + filterComplex + '" ' +
    '-map "[vout]" -c:v libx264 -crf 20 -preset fast "' + xfadeOut + '" 2>&1 && echo XFADE_OK';
  const out = run(xfadeCmd, 600000);
  if (!out.includes('XFADE_OK'))
    throw new Error('xfade failed: ' + out.slice(-500));
  withTransitions = xfadeOut;
}

// ━ STEP 4: Write ASS subtitle file (Premium Highlighting) ━━━━━━━━
function toAssTime(sec) {
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = Math.floor(sec % 60);
  const ms = Math.floor((sec % 1) * 100);
  return h + ':' + String(m).padStart(2,"0") + ':' + String(s).padStart(2,"0") + '.' + String(ms).padStart(2,"0");
}

let ass = `[Script Info]\nScriptType: v4.00+\nPlayResX: 1080\nPlayResY: 1920\n\n[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\nStyle: Default,Arial,70,&H00FFFFFF,&H000000FF,&H00000000,&HA0000000,1,0,1,4,2,2,60,60,320,1\n\n[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n`;

for (const group of subtitleChunks) {
  const words = group.words || [];
  if (!words.length) continue;

  const chunkEnd = words[words.length - 1].end;

  for (let i = 0; i < words.length; i++) {
    const lineStart = words[i].start;
    // Stretch each line to next word start — closes gaps that cause blinking
    const lineEnd = (i < words.length - 1) ? words[i + 1].start : chunkEnd;

    // Fade in on chunk open, fade out on chunk close
    let fadeTag = '';
    if      (i === 0 && words.length > 1)  fadeTag = '{\\fad(80,0)}';
    else if (i === words.length - 1)        fadeTag = '{\\fad(0,80)}';
    else if (words.length === 1)            fadeTag = '{\\fad(80,80)}';

    // Color-only highlight — no scale change avoids layout jitter
    let displayText = fadeTag;
    for (let j = 0; j < words.length; j++) {
      if (i === j) {
        displayText += '{\\c&H0000FFFF&}' + words[j].text + '{\\c&HFFFFFF&}';
      } else {
        displayText += words[j].text;
      }
      if (j < words.length - 1) displayText += ' ';
    }
    ass += 'Dialogue: 0,' + toAssTime(lineStart) + ',' + toAssTime(lineEnd) + ',Default,,0,0,0,,' + displayText + '\n';
  }
}
const assN8nPath = n8nIn + '/' + jobId + '.ass';
fs.writeFileSync(assN8nPath, ass, 'utf-8');

// ━ STEP 5: Final ─ video + narration audio + burned subtitles ━━━━
const assContPath  = contIn  + '/' + jobId + '.ass';
const audioContPath = contIn + '/' + jobId + '_narration.mp3';
const finalContPath = contOut + '/' + jobId + '_final.mp4';
// Get exact audio duration so video = audio length exactly
const probeOut = run(
  'docker exec ffmpeg-runner ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + audioContPath + '"',
  15000
);
const exactAudioDur = parseFloat(probeOut.trim()) || audioDuration;
const clipsDuration = N * CLIP_DUR - (N - 1) * FADE_DUR;
const stopDuration  = Math.max(0, exactAudioDur - clipsDuration);
console.log('Audio: ' + exactAudioDur.toFixed(3) + 's | Clips: ' + clipsDuration.toFixed(1) + 's | FadeToBlack: ' + stopDuration.toFixed(3) + 's');
// tpad extends with black frames, then fade filter fades the last stopDuration seconds to black
// Result: smooth cinematic fade to black while audio finishes — no frozen frame
const subFilter = "subtitles='" + assContPath + "',tpad=stop_mode=add:color=black:stop_duration=" + stopDuration.toFixed(3) + ",fade=t=out:st=" + clipsDuration.toFixed(3) + ":d=" + stopDuration.toFixed(3);

const finalCmd =
  'docker exec ffmpeg-runner ffmpeg -y ' +
  '-i "' + withTransitions + '" ' +
  '-i "' + audioContPath + '" ' +
  '-vf "' + subFilter + '" ' +
  '-c:v libx264 -crf 17 -preset medium ' +
  '-c:a aac -b:a 192k ' +
  '-movflags +faststart ' +
  '-shortest ' +
  '"' + finalContPath + '" 2>&1 && echo FINAL_OK';

const finalOut = run(finalCmd, 900000);
if (!finalOut.includes('FINAL_OK'))
  throw new Error('Final assembly failed: ' + finalOut.slice(-600));

const n8nFinalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(n8nFinalPath))
  throw new Error('Final video missing: ' + n8nFinalPath);

return [{ json: {
  ...data,
  output_filename:  jobId + '_final.mp4',
  final_video_path: n8nFinalPath,
  clips_used:       N,
  audio_duration:   audioDuration
}}];

const fs = require('fs');
const item = $input.first().json;
const filePath = item.final_video_path;

if (!fs.existsSync(filePath)) {
  throw new Error('Final video not found at: ' + filePath);
}

const buffer = fs.readFileSync(filePath);

return [{
  json: item,
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'video/mp4',
      fileName: item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode    = $('Upload Animation to Drive').first().json;
const assembleData = $('Assemble Video').first().json;
const fileId = driveNode.id;

// assembleData spreads the full original payload (including sheet_row, topic, title, etc.)
// Works for both Webhook path and Manual Trigger path
const videoUrl      = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec = Math.round((Date.now() - assembleData.start_time) / 1000);

console.log('Stage 2 complete. Job: ' + assembleData.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');

return [{ json: {
  job_id:              assembleData.job_id,
  topic:               assembleData.topic,
  title:               assembleData.title,
  video_url:           videoUrl,
  drive_file_id:       fileId,
  render_time_seconds: renderTimeSec,
  sheet_row:           assembleData.sheet_row,
  status:              'stage2_complete'
} }];

const assemble   = $('Assemble Video').first().json;
const stage2Done = $('Stage 2 Done').first().json;
return [{ json: {
  job_id:           stage2Done.job_id,
  title:            stage2Done.title,
  topic:            stage2Done.topic,
  narration:        assemble.narration || '',
  description:      assemble.narration ? assemble.narration.slice(0, 300) + '...' : (stage2Done.topic + ' – explained simply.'),
  hashtags:         assemble.hashtags || '',
  final_video_path: assemble.final_video_path,
  output_filename:  assemble.output_filename,
  drive_file_id:    stage2Done.drive_file_id,
  drive_video_url:  stage2Done.video_url,
  sheet_row:        stage2Done.sheet_row,
  callback_url:     null
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const clipPrompts = data.clip_prompts;
const negativePrompts = data.negative_prompts || [];
const defaultNeg = 'text, letters, alphabet, messy, distorted, watermark';

if (!Array.isArray(clipPrompts) || clipPrompts.length === 0)
  throw new Error('No clip_prompts in payload');

const audioDuration = data.audio_duration || 30;
const clipsNeeded   = clipPrompts.length; // Stage 1 already calculated exact count (6 for 30s)
console.log('Audio duration: ' + audioDuration.toFixed(1) + 's → generating ' + clipsNeeded + ' clips (5s each)');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-v1-lite-t2v-720p',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': buf.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch(e) { reject(new Error('Bad JSON from Wavespeed')); }
      });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const submitPromises = [];
for (let i = 0; i < clipsNeeded; i++) {
  submitPromises.push(
    apiPost({
      prompt:          clipPrompts[i],
      negative_prompt: negativePrompts[i] || defaultNeg,
      aspect_ratio:    '9:16',
      duration:        5,
      seed:            -1
    })
  );
}

const results = await Promise.all(submitPromises);

const task_ids = [];
for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id) throw new Error('Wavespeed submit failed: ' + JSON.stringify(r));
  task_ids.push(r.data.id);
}

return [{ json: {
  ...data,
  task_ids,
  clips_count: clipsNeeded,
  video_urls:  new Array(clipsNeeded).fill(null),
  poll_attempt: 0,
  all_done:    false
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const task_ids   = data.task_ids;
const video_urls = [...(data.video_urls || [null, null, null])];
const attempt    = (data.poll_attempt || 0) + 1;

console.log('--- Poll attempt #' + attempt + ' ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId + '/result',
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const raw = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(raw)); }
        catch(e) { reject(new Error('Non-JSON from Wavespeed status [HTTP ' + res.statusCode + ']: ' + raw.slice(0,200))); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// Check each clip that is not yet complete
for (let i = 0; i < task_ids.length; i++) {
  if (video_urls[i] !== null) {
    console.log('Clip ' + i + ' already done, skipping');
    continue;
  }

  const r = await apiGet(task_ids[i]);
  const status = (r.data && r.data.status) || 'unknown';
  console.log('Clip ' + i + ' [' + task_ids[i] + '] status: ' + status);

  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Clip ' + i + ' completed but output URL missing');
    video_urls[i] = url;
    console.log('Clip ' + i + ' ready: ' + url);
  } else if (status === 'failed') {
    throw new Error('Clip ' + i + ' FAILED: ' + JSON.stringify(r.data));
  } else {
    console.log('Clip ' + i + ' still ' + status + ' – will retry in 20s');
  }
}

const all_done = video_urls.every(u => u !== null) ? 1 : 0;
const pending  = video_urls.filter(u => u === null).length;

if (all_done === 1) {
  console.log('All clips are ready! Proceeding to assembly.');
} else {
  console.log(pending + ' clip(s) still generating. Waiting 20s before next poll.');
}

return [{ json: {
  ...data,
  task_ids,
  video_urls,
  poll_attempt: attempt,
  all_done
}}];
